124	function deriveDueAt(now, nextStep) {
125	  const match = /by\s+(\d{1,2}):(\d{2})/.exec(nextStep ?? "");
126	  if (!match) {
127	    return now;
128	  }
129	
130	  const dueAt = new Date(now);
131	  if (Number.isNaN(dueAt.getTime())) {
132	    return now;
133	  }
134	
135	  dueAt.setUTCHours(Number(match[1]), Number(match[2]), 0, 0);
136	  return dueAt.toISOString();
137	}
